#include <iostream>
#include <map>
using namespace std;
map<string,int> mmap;
map<string,int>::iterator it;
int main()
{
    int n;
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        string s;
        cin>>s;
        mmap[s]++;
    }
    for(int i=1;i<=n-1;i++)
    {
        string s;
        cin>>s;
        mmap[s]--;
    }
    for(it=mmap.begin();it!=mmap.end();it++)
    {
        if(it->second!=0)
        {
            cout<<it->first;
            break;
        }
    }
    return 0;
}
